import{K as r}from"./index-DhMRJaqL.js";const a={preview(t){return r.get("/subscriptions/preview",{params:{url:t}})},sync(t){return r.post(`/subscriptions/${t}/sync`)},list(t,s){return r.get(`/subscriptions/${t}/articles`,{params:s})},all(t){return r.get("/subscriptions/articles",{params:t})},getUnreadCount(){return r.get("/subscriptions/unread-count")},get(t){return r.get(`/subscriptions/articles/${t}`)},markAsRead(t,s=!0){return r.patch(`/subscriptions/articles/${t}/read`,{isRead:s})},batchMarkAsRead(t,s=!0){return r.post("/subscriptions/batch-read",{articleIds:t,isRead:s})},markAllAsRead(t){return r.post(`/subscriptions/${t}/mark-all-read`)},markAllAsReadGlobal(){return r.post("/subscriptions/mark-all-read")},toggleFavorite(t){return r.patch(`/subscriptions/articles/${t}/favorite`)},extractFullContent(t){return r.post(`/subscriptions/articles/${t}/extract`,{},{timeout:6e4})},download(t,s="md"){return r.get(`/subscriptions/articles/${t}/download`,{params:{format:s},responseType:"blob"})},delete(t){return r.delete(`/subscriptions/articles/${t}`)},generateShareLink(t){return r.post(`/subscriptions/articles/${t}/share`)},batchDelete(t){return r.post("/subscriptions/articles/batch-delete",{articleIds:t})},cleanup(t){return r.post("/subscriptions/articles/cleanup",t)},getStats(){return r.get("/subscriptions/stats")}};export{a};
